// Rachel  21m00Tcm4TlvDq8ikWAM — warm, clear female (lecture-bestie)
// Elli    MF3mGyEYCl7XYWbV9V6O — young, energetic female (exam-gremlin)
// Josh    TxGEqnHWrfWFTfGW9XjX — deep, focused male (problem-grinder)
// Antoni  ErXwobaYiN019PkySvjV — approachable, playful male (doodle-prof)
// Sam     yoZ06aMxZJJ28mfd3POQ — raspy, laid-back male (meme-lord)
const VOICE_MAP = {
  'lecture-bestie':  { voice: '21m00Tcm4TlvDq8ikWAM', stability: 0.75, similarity_boost: 0.75 },
  'exam-gremlin':    { voice: 'MF3mGyEYCl7XYWbV9V6O', stability: 0.30, similarity_boost: 0.60 },
  'problem-grinder': { voice: 'TxGEqnHWrfWFTfGW9XjX', stability: 0.85, similarity_boost: 0.80 },
  'doodle-prof':     { voice: 'ErXwobaYiN019PkySvjV', stability: 0.40, similarity_boost: 0.70 },
  'meme-lord':       { voice: 'yoZ06aMxZJJ28mfd3POQ', stability: 0.25, similarity_boost: 0.65 },
};

const items = $input.all();
return items.map(item => {
  const cfg = VOICE_MAP[item.json.persona_slug] ?? VOICE_MAP['lecture-bestie'];
  const ttsText =
    `Here is your ${item.json.post_type} for today.\n\n${item.json.chunk_text.slice(0, 800)}`;
  return {
    json: {
      ...item.json,
      tts_text:             ttsText,
      tts_voice:            cfg.voice,
      tts_stability:        cfg.stability,
      tts_similarity_boost: cfg.similarity_boost,
      tts_title:            item.json.title ?? item.json.chunk_text.slice(0, 120),
    }
  };
});

const item   = $input.first().json;
const apiKey = $vars.ELEVENLABS_API_KEY;

const response = await fetch(
  `https://api.elevenlabs.io/v1/text-to-speech/${item.tts_voice}`,
  {
    method: 'POST',
    headers: {
      'xi-api-key':   apiKey,
      'Content-Type': 'application/json',
      'Accept':       'audio/mpeg',
    },
    body: JSON.stringify({
      text:     item.tts_text,
      model_id: 'eleven_turbo_v2_5',
      voice_settings: {
        stability:        item.tts_stability,
        similarity_boost: item.tts_similarity_boost,
      },
    }),
  }
);

if (!response.ok) {
  const err = await response.text();
  throw new Error(`ElevenLabs TTS failed: ${response.status} — ${err}`);
}

const audioBuffer = await response.arrayBuffer();
const audioB64    = Buffer.from(audioBuffer).toString('base64');
const filePath    = `${item.material_id}/${item.persona_slug}-${item.chunk_index}-audio.mp3`;

return [{
  json: {
    ...item,
    audio_b64: audioB64,
    mime_type: 'audio/mpeg',
    file_path: filePath,
  },
  binary: {
    audio_data: {
      data:     audioB64,
      mimeType: 'audio/mpeg',
      fileName: `${item.persona_slug}-${item.chunk_index}-audio.mp3`,
    },
  },
}];

const prev        = $('Call ElevenLabs TTS').first().json;
const supabaseUrl = $vars.SUPABASE_URL;
const mediaUrl    = `${supabaseUrl}/storage/v1/object/public/post-media/${prev.file_path}`;
return [{
  json: {
    material_id: prev.material_id,
    persona_id:  prev.persona_id,
    post_type:   prev.post_type,
    title:       prev.tts_title ?? null,
    body:        prev.chunk_text.slice(0, 300),
    media_type:  'audio',
    media_url:   mediaUrl,
    source:      'n8n',
    sort_order:  prev.chunk_index * 4 + 2,
  }
}];
